# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

typedef struct {
    int *handles;
    int count;
    int capacity;
} FileHandleList;

FileHandleList* create_handle_list() {
    FileHandleList *list = (FileHandleList*)malloc(sizeof(FileHandleList));
    if (!list) return NULL;
    
    list->handles = (int*)malloc(10 * sizeof(int));
    if (!list->handles) {
        free(list);
        return NULL;
    }
    
    list->count = 0;
    list->capacity = 10;
    return list;
}

int add_handle(FileHandleList *list, int handle) {
    if (!list) return -1;
    
    if (list->count >= list->capacity) {
        list->capacity *= 2;
        int *new_handles = (int*)realloc(list->handles, list->capacity * sizeof(int));
        if (!new_handles) return -1;
        list->handles = new_handles;
    }
    
    list->handles[list->count++] = handle;
    return 0;
}

int remove_handle(FileHandleList *list, int handle) {
    if (!list) return -1;
    
    for (int i = 0; i < list->count; i++) {
        if (list->handles[i] == handle) {
            // Shift elements
            for (int j = i; j < list->count - 1; j++) {
                list->handles[j] = list->handles[j + 1];
            }
            list->count--;
            return 0;
        }
    }
    return -1;
}

void cleanup_handle_list(FileHandleList **list_ptr) {
    if (!list_ptr || !*list_ptr) return;
    
    FileHandleList *list = *list_ptr;
    
    // Close all file descriptors
    for (int i = 0; i < list->count; i++) {
        close(list->handles[i]);
    }
    
    // Free memory
    free(list->handles);
    free(list);
    
    *list_ptr = NULL;
}